// Filter items from the last 24 hours
const cutoff = new Date(Date.now() - 24 * 60 * 60 * 1000);
const items = $input.all();
const recent = items.filter(item => {
  const pubDate = item.json.pubDate || item.json.isoDate || item.json.date;
  if (!pubDate) return true; // keep items without dates for safety
  return new Date(pubDate) >= cutoff;
});
return recent.length > 0 ? recent : [{ json: { _empty: true } }];

