// Merge the Claude-extracted update into the current eipp-data.json
const githubItem = $('Get Current Data from GitHub').first();
const sha = githubItem.json.sha;
const currentContent = Buffer.from(githubItem.json.content, 'base64').toString('utf-8');
const data = JSON.parse(currentContent);

// Parse Claude's extraction response
let update;
try {
  const extractResponse = $input.first().json.content[0].text;
  const jsonMatch = extractResponse.match(/\{[\s\S]*\}/);
  update = JSON.parse(jsonMatch[0]);
} catch (e) {
  return [{ json: { _skip: true, reason: 'Failed to parse extraction response' } }];
}

// Apply project-level updates
if (update.projectId && update.updates) {
  const project = data.projects.find(p => p.id === update.projectId);
  if (project) {
    if (update.updates.milestone) project.milestone = update.updates.milestone;
    if (update.updates.otaStatus) project.otaStatus = update.updates.otaStatus;
    if (update.updates.appendNotes) project.notes += ' ' + update.updates.appendNotes;
    if (update.updates.newLinks && update.updates.newLinks.length) {
      project.links.push(...update.updates.newLinks);
    }
  }
}

// Apply meta-level updates
if (update.metaUpdates) {
  if (update.metaUpdates.bannerMessage) data.meta.bannerMessage = update.metaUpdates.bannerMessage;
  if (update.metaUpdates.globalOtaStatus) data.meta.globalOtaStatus = update.metaUpdates.globalOtaStatus;
}

// Update metadata
data.meta.lastUpdated = new Date().toISOString();
data.meta.updatedBy = 'n8n';
data.meta.version += 1;

// Add history entry
data.updateHistory.unshift({
  timestamp: new Date().toISOString(),
  source: 'n8n-auto-monitor',
  description: update.description || 'Auto-detected update',
  projectsAffected: update.projectId ? [update.projectId] : [],
  sourceUrl: $('Parse Relevance Response').first().json.originalUrl || ''
});

// Keep only last 50 history entries
data.updateHistory = data.updateHistory.slice(0, 50);

const updatedJson = JSON.stringify(data, null, 2);
const updatedBase64 = Buffer.from(updatedJson).toString('base64');

return [{
  json: {
    _skip: false,
    updatedContent: updatedBase64,
    sha: sha,
    commitMessage: 'auto: ' + (update.description || 'eIPP data update')
  }
}];
